fn dump_container_logs(name: &str) -> String {
    Command::new("docker")
        .args(["logs", "--tail", "30", name])
        .output()
        .map(|o| {
            let out = String::from_utf8_lossy(&o.stdout).to_string();
            let err = String::from_utf8_lossy(&o.stderr).to_string();
            format!("{out}\n{err}")
        })
        .unwrap_or_default()
}
